module top_module(input [2:0] sign_bit,
              output reg[7:0] extended
    );always @(sign_bit)begin
  if(sign_bit[2]==1)
   begin 
    extended[7:3]=5'b11111;
    extended[2:0]=sign_bit;
   end

   if(sign_bit[2]==0)begin 
   extended[7:3]=5'b00000;
   extended[2:0]=sign_bit;
   end
   end


endmodule
